// Site-wide JS enhancements. The nav, footer, and skip link are static HTML
// generated by tools/sync_chrome.py (edit the chrome there, then re-run it);
// this file only adds behavior that genuinely needs JavaScript: the back-to-
// top button, the mobile nav menu, scroll reveals, card tilt, and the video
// lightbox.
(function () {
    var TOP_SVG = '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="18 15 12 9 6 15"></polyline></svg>';

    // Mobile morphing-pill nav: the Menu button (hidden on desktop) expands
    // the pill into a dropdown card. All the visuals live in responsive.css
    // under nav.is-open; this only manages state, label, and scroll lock.
    function initNavMenu() {
        var nav = document.querySelector('nav[aria-label="Primary navigation"]');
        var btn = document.getElementById('nav-menu-btn');
        if (!nav || !btn) return;
        var label = document.getElementById('nav-menu-label');

        function setOpen(open) {
            nav.classList.toggle('is-open', open);
            document.body.classList.toggle('nav-open', open);
            btn.setAttribute('aria-expanded', String(open));
            if (label) label.textContent = open ? 'Close' : 'Menu';
        }

        window.toggleNavMenu = function () {
            setOpen(!nav.classList.contains('is-open'));
        };

        document.addEventListener('keydown', function (event) {
            if (event.key === 'Escape' && nav.classList.contains('is-open')) {
                setOpen(false);
                btn.focus();
            }
        });
        // A tap on any link closes the menu; mostly relevant for the rare
        // same-page navigation, since a real navigation resets everything.
        nav.querySelector('.nav-links').addEventListener('click', function (event) {
            if (event.target.closest('a')) setOpen(false);
        });
        // Crossing back to the desktop layout must never leave the body
        // scroll-locked by a menu that no longer exists.
        window.matchMedia('(min-width: 769px)').addEventListener('change', function (event) {
            if (event.matches) setOpen(false);
        });
    }

    // Scroll reveal: both selectors must mirror the :is() list in base.css,
    // or an element would start hidden that no observer ever reveals.
    // Children of a stagger container reveal together, offset by index,
    // when the container enters the viewport.
    var REVEAL_SELECTOR = '.page-hero, .section-header, .hero-card, .glass-card, .section-cta, .cta-section, .code-cta, .carousel-container, .coming-soon, .article-backbar, .article-wrap';
    var STAGGER_SELECTOR = '.featured-grid, .bento-grid';

    function initReveal() {
        function showNow(el) { el.classList.add('in-view'); }

        // The reveal transition is inline (not a CSS class) so the
        // element's stylesheet transitions, e.g. the card hover lift,
        // come back untouched once the reveal has finished.
        function reveal(el, delay) {
            setTimeout(function () {
                el.style.transition = 'opacity 0.65s ease, transform 0.65s cubic-bezier(0.2, 0.8, 0.2, 1)';
                el.classList.add('in-view');
                setTimeout(function () { el.style.transition = ''; }, 700);
            }, delay);
        }

        // groups: [element to watch, elements revealed (staggered) when it shows]
        var groups = [];
        document.querySelectorAll(STAGGER_SELECTOR).forEach(function (grid) {
            groups.push([grid, Array.prototype.slice.call(grid.children)]);
        });
        document.querySelectorAll(REVEAL_SELECTOR).forEach(function (el) {
            if (el.closest(STAGGER_SELECTOR)) return; // revealed with its grid
            groups.push([el, [el]]);
        });

        if (window.matchMedia('(prefers-reduced-motion: reduce)').matches ||
            !('IntersectionObserver' in window)) {
            groups.forEach(function (group) { group[1].forEach(showNow); });
            return;
        }

        var byTarget = new Map();
        var observer = new IntersectionObserver(function (entries) {
            entries.forEach(function (entry) {
                if (!entry.isIntersecting) return;
                observer.unobserve(entry.target);
                byTarget.get(entry.target).forEach(function (el, i) {
                    reveal(el, i * 90);
                });
            });
        }, { rootMargin: '0px 0px -8% 0px' });

        groups.forEach(function (group) {
            // Elements that start display:none (the contact form's success
            // panel) never intersect; mark them revealed now so they're
            // fully visible whenever other code shows them.
            if (getComputedStyle(group[0]).display === 'none') {
                group[1].forEach(showNow);
                return;
            }
            byTarget.set(group[0], group[1]);
            observer.observe(group[0]);
        });
    }

    // Pointer tilt: [data-tilt] cards rotate a few degrees toward the
    // cursor (hover-capable, fine-pointer devices only). The inline
    // transform overrides the CSS hover lift while the pointer is over
    // the card and is cleared on leave, handing back to the stylesheet.
    function initTilt() {
        if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
        if (!window.matchMedia('(hover: hover) and (pointer: fine)').matches) return;
        var MAX_DEG = 5;
        document.querySelectorAll('[data-tilt]').forEach(function (card) {
            var frame = null;
            var lastEvent = null;
            card.addEventListener('pointermove', function (event) {
                lastEvent = event;
                if (frame) return;
                frame = requestAnimationFrame(function () {
                    frame = null;
                    var rect = card.getBoundingClientRect();
                    var dx = (lastEvent.clientX - rect.left) / rect.width - 0.5;
                    var dy = (lastEvent.clientY - rect.top) / rect.height - 0.5;
                    card.style.transform =
                        'perspective(900px) translateY(-6px)' +
                        ' rotateX(' + (-dy * MAX_DEG).toFixed(2) + 'deg)' +
                        ' rotateY(' + (dx * MAX_DEG).toFixed(2) + 'deg)';
                });
            });
            card.addEventListener('pointerleave', function () {
                if (frame) { cancelAnimationFrame(frame); frame = null; }
                card.style.transform = '';
            });
        });
    }

    function addBackToTop() {
        var btn = document.createElement('button');
        btn.id = 'back-to-top';
        btn.setAttribute('aria-label', 'Back to top');
        btn.title = 'Back to top';
        btn.innerHTML = TOP_SVG;
        document.body.appendChild(btn);
        window.addEventListener('scroll', function () {
            btn.classList.toggle('visible', window.scrollY > 300);
        }, { passive: true });
        btn.addEventListener('click', function () {
            window.scrollTo({ top: 0, behavior: 'smooth' });
        });
    }

    // Autoplaying demo videos should hold still for reduced-motion users.
    function respectReducedMotion() {
        if (!window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
        document.querySelectorAll('video[autoplay]').forEach(function (v) {
            v.removeAttribute('autoplay');
            v.pause();
        });
    }

    function init() {
        initNavMenu();
        initReveal();
        initTilt();
        addBackToTop();
        respectReducedMotion();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();

// Demo video that doesn't sit inside a cropped card preview (e.g. the
// KanaCard case study): clicking just toggles play/pause, since the
// full picture is already visible at its natural aspect ratio.
window.toggleCardVideo = function (event, wrap) {
    event.preventDefault();
    event.stopPropagation();
    var video = wrap.querySelector('video');
    if (!video) return;
    if (video.paused) {
        video.play();
    } else {
        video.pause();
    }
};

// Full-video lightbox: for card previews that crop a portrait recording
// to fit a grid cell (e.g. the homepage Rogue Roll card), clicking opens
// an overlay with the uncropped video at its natural aspect ratio. The
// overlay is a fixed-position layer built once and reused, so opening it
// never touches the surrounding grid's layout or the other cards' size.
(function () {
    var modal, modalVideo, opener;

    function build() {
        if (modal) return;
        modal = document.createElement('div');
        modal.className = 'video-modal';
        modal.setAttribute('role', 'dialog');
        modal.setAttribute('aria-modal', 'true');
        modal.innerHTML =
            '<button type="button" class="video-modal-close" aria-label="Close video">' +
            '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>' +
            '</button>' +
            '<video class="video-modal-video" controls loop playsinline></video>';
        modal.addEventListener('click', function (event) {
            if (event.target === modal) close();
        });
        // aria-modal promises focus stays inside; keep Tab cycling between
        // the close button and the video's native controls.
        modal.addEventListener('keydown', function (event) {
            if (event.key !== 'Tab') return;
            var focusables = modal.querySelectorAll('button, video');
            var first = focusables[0];
            var last = focusables[focusables.length - 1];
            if (event.shiftKey && document.activeElement === first) {
                event.preventDefault();
                last.focus();
            } else if (!event.shiftKey && document.activeElement === last) {
                event.preventDefault();
                first.focus();
            }
        });
        modal.querySelector('.video-modal-close').addEventListener('click', close);
        document.body.appendChild(modal);
        modalVideo = modal.querySelector('video');
    }

    function close() {
        if (!modal) return;
        modal.classList.remove('is-open');
        document.body.classList.remove('video-modal-open');
        modalVideo.pause();
        // Hand focus back to the button that launched the lightbox.
        if (opener && document.contains(opener)) opener.focus();
        opener = null;
    }

    document.addEventListener('keydown', function (event) {
        if (event.key === 'Escape' && modal && modal.classList.contains('is-open')) close();
    });

    window.openVideoModal = function (event, src, label, poster) {
        event.preventDefault();
        event.stopPropagation();
        build();
        opener = event.currentTarget || document.activeElement;
        modalVideo.src = src;
        modalVideo.poster = poster || '';
        modalVideo.setAttribute('aria-label', label || 'Demo video');
        modal.setAttribute('aria-label', label || 'Demo video');
        modal.classList.add('is-open');
        document.body.classList.add('video-modal-open');
        modalVideo.currentTime = 0;
        modalVideo.play();
        modal.querySelector('.video-modal-close').focus();
    };
})();
